/**
 * MedX button runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Button variants, loading states, and action handlers for supply-chain operations.
 */
const BUTTON_VARIANTS = Object.freeze({
  default: { bg: "bg-primary", text: "text-primary-foreground", hover: "hover:bg-primary/90" },
  secondary: { bg: "bg-secondary", text: "text-secondary-foreground", hover: "hover:bg-secondary/80" },
  outline: { bg: "bg-transparent", text: "text-foreground", border: "border border-input" },
  ghost: { bg: "bg-transparent", text: "text-foreground", hover: "hover:bg-accent" },
  destructive: { bg: "bg-destructive", text: "text-destructive-foreground", hover: "hover:bg-destructive/90" },
  link: { bg: "bg-transparent", text: "text-primary", underline: "underline-offset-4" },
});

const BUTTON_SIZES = Object.freeze({
  sm: { height: "h-8", padding: "px-3", text: "text-xs" },
  md: { height: "h-9", padding: "px-4", text: "text-sm" },
  lg: { height: "h-10", padding: "px-6", text: "text-sm" },
  icon: { height: "h-9", width: "w-9", padding: "p-0" },
});

const BUTTON_ACTIONS = Object.freeze({
  receiveBatch: { label: "Receive batch", variant: "default", icon: "package-plus" },
  dispatchOrder: { label: "Dispatch order", variant: "default", icon: "truck" },
  quarantineLot: { label: "Quarantine", variant: "destructive", icon: "alert-triangle" },
  exportCsv: { label: "Export CSV", variant: "outline", icon: "download" },
  connectWallet: { label: "Connect wallet", variant: "secondary", icon: "wallet" },
  approvePo: { label: "Approve PO", variant: "default", icon: "check" },
});

const buttonRegistry = new Map();
let buttonIdSeq = 0;

function createButton(config) {
  const action = config.action ? BUTTON_ACTIONS[config.action] : null;
  const id = config.id ?? `medx-button-${++buttonIdSeq}`;
  const button = {
    id,
    label: config.label ?? action?.label ?? "Button",
    variant: config.variant ?? action?.variant ?? "default",
    size: config.size ?? "md",
    styles: BUTTON_VARIANTS[config.variant ?? action?.variant ?? "default"],
    sizeStyles: BUTTON_SIZES[config.size ?? "md"],
    icon: config.icon ?? action?.icon ?? null,
    loading: false,
    disabled: Boolean(config.disabled),
    onClick: typeof config.onClick === "function" ? config.onClick : null,
    createdAt: Date.now(),
  };
  buttonRegistry.set(id, button);
  return button;
}

function setButtonLoading(id, loading) {
  const button = buttonRegistry.get(id);
  if (!button) return false;
  button.loading = Boolean(loading);
  return true;
}

async function clickButton(id) {
  const button = buttonRegistry.get(id);
  if (!button || button.disabled || button.loading) return null;
  setButtonLoading(id, true);
  const result = { buttonId: id, label: button.label, clickedAt: Date.now() };
  if (button.onClick) await button.onClick(result);
  setButtonLoading(id, false);
  return result;
}

async function runMedxButton() {
  console.log("[medx:ui:button] runtime initialized");
  console.log(`[medx:ui:button] variants=${Object.keys(BUTTON_VARIANTS).length} actions=${Object.keys(BUTTON_ACTIONS).length}`);

  const clicks = [];
  const receive = createButton({ action: "receiveBatch", onClick: () => clicks.push("receive") });
  const quarantine = createButton({ action: "quarantineLot", size: "sm" });
  createButton({ action: "exportCsv", variant: "outline" });

  await clickButton(receive.id);
  console.log(`[medx:ui:button] registered=${buttonRegistry.size} clicks=${clicks.join(",")}`);
  console.log("[medx:ui:button] bootstrap complete");
}

module.exports = runMedxButton;
